\begin{itemize}
  \item Suppose \(n\) is a nonnegative integer. A \emph{list} of \emph{length} \(n\) is an ordered collection of \(n\) elements (which might be numbers, other lists, or more abstract objects).
  \item Two lists are equal if and only if they have the same length and the same elements in the same order.
\end{itemize}

\begin{itemize}
  \item An \emph{addition} on a set \(V\) is a function that assigns an element \(u + v \in V\) to each pair of elements \(u, v \in V\).
  \item A \emph{scalar multiplication} on a set \(V\) is a function that assigns an element \(\lambda v \in V\) to each \(\lambda \in \mathbb{F}\) and each \(v \in V\).
\end{itemize}

\begin{itemize}
  \item A vector space over \( \mathbf{R} \) is called a \emph{real vector space}.
  \item A vector space over \( \mathbf{C} \) is called a \emph{complex vector space}.
\end{itemize}

Suppose $V_1, \ldots, V_m$ are subspaces of $V$.
\begin{itemize}
  \item The sum $V_1 + \cdots + V_m$ is called a \textit{direct sum} if each element of $V_1 + \cdots + V_m$ can be written in only one way as a sum $v_1 + \cdots + v_m$, where each $v_k \in V_k$.
  \item If $V_1 + \cdots + V_m$ is a direct sum, then $V_1 \oplus \cdots \oplus V_m$ denotes $V_1 + \cdots + V_m$, with the $\oplus$ notation serving as an indication that this is a direct sum.
\end{itemize}

\begin{itemize}
  \item The \emph{dimension} of a finite-dimensional vector space is the length of any basis of the vector space.
  \item The dimension of a finite-dimensional vector space \(V\) is denoted by \(\dim V\).
\end{itemize}

The sum of two matrices of the same size is the matrix obtained by adding corresponding entries in the matrices:
\[
  \begin{pmatrix}
    A_{1,1} & \cdots & A_{1,n} \\
    \vdots  & \ddots & \vdots  \\
    A_{m,1} & \cdots & A_{m,n}
  \end{pmatrix}
  +
  \begin{pmatrix}
    C_{1,1} & \cdots & C_{1,n} \\
    \vdots  & \ddots & \vdots  \\
    C_{m,1} & \cdots & C_{m,n}
  \end{pmatrix}
  =
  \begin{pmatrix}
    A_{1,1}+C_{1,1} & \cdots & A_{1,n}+C_{1,n} \\
    \vdots          & \ddots & \vdots          \\
    A_{m,1}+C_{m,1} & \cdots & A_{m,n}+C_{m,n}
  \end{pmatrix}.
\]

The product of a scalar and a matrix is the matrix obtained by multiplying each entry in the matrix by the scalar:
\[
  \lambda
  \begin{pmatrix}
    A_{1,1} & \cdots & A_{1,n} \\
    \vdots  & \ddots & \vdots  \\
    A_{m,1} & \cdots & A_{m,n}
  \end{pmatrix}
  =
  \begin{pmatrix}
    \lambda A_{1,1} & \cdots & \lambda A_{1,n} \\
    \vdots          & \ddots & \vdots          \\
    \lambda A_{m,1} & \cdots & \lambda A_{m,n}
  \end{pmatrix}.
\]

Suppose \(A\) is an \(m\)-by-\(n\) matrix with entries in \(\mathbb{F}\).
\begin{itemize}
  \item The \emph{column rank} of \(A\) is the dimension of the span of the columns of \(A\) in \(\mathbb{F}^{m,1}\).
  \item The \emph{row rank} of \(A\) is the dimension of the span of the rows of \(A\) in \(\mathbb{F}^{1,n}\).
\end{itemize}

\begin{itemize}
  \item A linear map \(T\in\mathcal{L}(V,W)\) is called \emph{invertible} if there exists a linear map \(S\in\mathcal{L}(W,V)\) such that \(ST\) equals the identity operator on \(V\) and \(TS\) equals the identity operator on \(W\).
  \item A linear map \(S\in\mathcal{L}(W,V)\) satisfying \(ST = I\) and \(TS = I\) is called an \emph{inverse} of \(T\) (where the first \(I\) is the identity on \(V\) and the second \(I\) is the identity on \(W\)).
\end{itemize}

\begin{itemize}
  \item An \emph{isomorphism} is an invertible linear map.
  \item Two vector spaces are called \emph{isomorphic} if there is an isomorphism from one vector space onto the other.
\end{itemize}

Suppose \(z = a + bi\), where \(a\) and \(b\) are real numbers.
\begin{itemize}
\item The \emph{real part} of \(z\), denoted by \(\Re z\), is defined by \(\Re z = a\).
\item The \emph{imaginary part} of \(z\), denoted by \(\Im z\), is defined by \(\Im z = b\).
\end{itemize}

\begin{itemize}
\item Two operators $S$ and $T$ on the same vector space \emph{commute} if $ST = TS$.
\item Two square matrices $A$ and $B$ of the same size \emph{commute} if $AB = BA$.
\end{itemize}

An inner product on $V$ is a function that takes each ordered pair $(u,v)$ of elements of $V$ to a number $\langle u,v\rangle\in F$ and has the following properties.

\textbf{positivity}

$\langle v,v\rangle \ge 0$ for all $v\in V$.

\textbf{definiteness}

$\langle v,v\rangle = 0$ if and only if $v=0$.

\textbf{additivity in first slot}

$\langle u+v,w\rangle = \langle u,w\rangle + \langle v,w\rangle$ for all $u,v,w\in V$.

\textbf{homogeneity in first slot}

$\langle \lambda u,v\rangle = \lambda\langle u,v\rangle$ for all $\lambda\in F$ and all $u,v\in V$.

\textbf{conjugate symmetry}

$\langle u,v\rangle = \langle v,u\rangle$ for all $u,v\in V$.

\begin{itemize}
  \item A list of vectors is called \emph{orthonormal} if each vector in the list has norm 1 and is orthogonal to all the other vectors in the list.
  \item In other words, a list \(e_1, \ldots, e_m\) of vectors in \(V\) is orthonormal if
  \[
    \langle e_j, e_k \rangle =
    \begin{cases}
      1 & \text{if } j = k, \\
      0 & \text{if } j \ne k
    \end{cases}
  \]
  for all \(j, k \in \{1, \ldots, m\}\).
\end{itemize}

\begin{itemize}
  \item A \emph{linear functional} on \(V\) is a linear map from \(V\) to \(\mathbf{F}\).
  \item The \emph{dual space} of \(V\), denoted by \(V'\), is the vector space of all linear functionals on \(V\). In other words, \(V' = \mathcal{L}(V, \mathbf{F})\).
\end{itemize}

\begin{itemize}
  \item An operator on an inner product space is called \emph{normal} if it commutes with its adjoint.
  \item In other words, \(T \in \mathcal{L}(V)\) is normal if \(TT^* = T^*T\).
\end{itemize}

Suppose \(m\) is a positive integer.
\begin{itemize}
  \item An \(m\)-linear form \(\alpha\) on \(V\) is called \emph{alternating} if \(\alpha(v_1, \ldots, v_m) = 0\) whenever \(v_1, \ldots, v_m\) is a list of vectors in \(V\) with \(v_j = v_k\) for some two distinct values of \(j\) and \(k\) in \(\{1, \ldots, m\}\).
  \item \(V^{(m)}_{\text{alt}} = \{ \alpha \in V^{(m)} : \alpha \text{ is an alternating } m\text{-linear form on } V \}\).
\end{itemize}

Suppose \(m\) is a positive integer.
\begin{itemize}
  \item A \emph{permutation} of \((1, \ldots, m)\) is a list \((j_1, \ldots, j_m)\) that contains each of the numbers \(1, \ldots, m\) exactly once.
  \item The set of all permutations of \((1, \ldots, m)\) is denoted by \(\text{perm } m\).
\end{itemize}

\begin{itemize}
  \item A \emph{bilinear functional} on \(V \times W\) is a function \(\beta : V \times W \to \mathbb{F}\) such that \(v \mapsto \beta(v, w)\) is a linear functional on \(V\) for each \(w \in W\) and \(w \mapsto \beta(v, w)\) is a linear functional on \(W\) for each \(v \in V\).
  \item The vector space of bilinear functionals on \(V \times W\) is denoted by \(\mathcal{B}(V, W)\).
\end{itemize}

\begin{itemize}
  \item An \emph{m-linear functional} on \(V_1 \times \cdots \times V_m\) is a function \(\beta : V_1 \times \cdots \times V_m \to \mathbb{F}\) that is a linear functional in each slot when the other slots are held fixed.
  \item The vector space of \(m\)-linear functionals on \(V_1 \times \cdots \times V_m\) is denoted by \(\mathcal{B}(V_1, \ldots, V_m)\).
\end{itemize}
